INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MNT001', 'bolt-nut-tightening-techniques', 'เทคนิคการขันยึดโบลท์และนัตอย่างถูกต้องเพื่อความเที่ยงตรง', 'Bolt and Nut Tightening Techniques', 'หลักสูตรเพื่อพัฒนาทักษะการขันยึดโบลท์และนัตอย่างถูกต้อง ลดการขัดข้องของเครื่องจักรจากปัญหาการขันไม่แน่นหรือขันแน่นเกินไป', 'ในโรงงานอุตสาหกรรม โบลท์และนัตเป็นชิ้นส่วนพื้นฐานที่พบในแทบทุกเครื่องจักร แม้จะดูเล็กน้อย แต่ปัญหาจากโบลท์และนัตเป็นหนึ่งในสาเหตุสำคัญที่ทำให้เกิดการขัดข้องหรือหยุดชะงักของกระบวนการผลิต หลักสูตรนี้เน้นพัฒนาทักษะการขันยึดให้ถูกต้องและปลอดภัย', 'MNT', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', '/images/courses/MNT001.png');
INSERT INTO course_objectives (course_id, objective, sort_order) VALUES (@course_id, 'เสริมสร้างทักษะ ความรู้ และความเข้าใจเกี่ยวกับประเภทของโบลท์และนัต แนวทางในการเลือกใช้อย่างเหมาะสม การประกอบ และการขันยึดให้แน่นอย่างถูกต้อง', 0);
