INSERT INTO course_objectives (course_id, objective, sort_order) VALUES (@course_id, 'เรียนรู้วิธีการตั้งค่าแรงบิด (Torque Setting) ที่เหมาะสม และฝึกทักษะการปฏิบัติตามลำดับการขันแน่นที่ถูกต้อง ทั้งในกรณีของหน้าแปลนกลม และหน้าแปลนเหลี่ยม', 2);
