INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MNT002', 'pneumatics-fundamentals', 'พื้นฐานระบบนิวเมติกส์ (Pneumatics)', 'Pneumatics Fundamentals', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะการทำงานกับระบบนิวเมติกส์ในโรงงานอุตสาหกรรม ลดความขัดข้องและเพิ่มประสิทธิภาพการผลิต', 'ระบบนิวเมติกส์เป็นระบบที่ใช้พลังงานจากลมอัดเพื่อแปลงเป็นพลังงานกล ในการใช้งานจริงมักพบปัญหาการทำงานล่าช้าหรือหยุดค้าง เนื่องจากการติดตั้งไม่ถูกต้อง การเดินท่อลมไม่เหมาะสม หรือการบำรุงรักษาที่ไม่เป็นระบบ หลักสูตรนี้เน้นให้บุคลากรสามารถวิเคราะห์ แก้ไข และป้องกันปัญหาได้อย่างมีประสิทธิภาพ', 'MNT', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
