INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MNT004', 'mechanical-power-transmission-maintenance', 'เทคนิคการบำรุงรักษาระบบส่งกำลังทางกล', 'Mechanical Power Transmission Maintenance Techniques', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะการบำรุงรักษาระบบส่งกำลังระหว่างมอเตอร์กับอุปกรณ์ต่างๆ ในโรงงานอุตสาหกรรม', 'ระบบส่งกำลังระหว่างมอเตอร์กับอุปกรณ์เช่น ปั๊ม เกียร์ พัดลม โบลเวอร์ และสปินเดิล มีหลายรูปแบบ ทั้งคัปปลิ้ง สายพาน และโซ่ การมีความรู้ในการเลือกใช้ บำรุงรักษา และวิเคราะห์ปัญหาอย่างถูกต้อง ช่วยลดการหยุดเครื่อง ลดต้นทุน และเพิ่มประสิทธิภาพการผลิต', 'MNT', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
