INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MNT005', 'machine-lubrication-maintenance', 'เทคนิคการบำรุงรักษางานหล่อลื่นเครื่องจักร', 'Machine Lubrication Maintenance Techniques', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะงานหล่อลื่นในระบบบำรุงรักษาเชิงป้องกัน เลือกใช้สารหล่อลื่นได้ถูกต้อง ลดต้นทุนและความเสียหายของเครื่องจักร', 'งานหล่อลื่นในระบบบำรุงรักษาเชิงป้องกัน (PM) เป็นงานที่สำคัญ หากขาดความรู้ความเข้าใจที่ถูกต้องตั้งแต่การเลือกชนิด เกรด มาตรฐาน จำนวน ปริมาณ และความถี่การหล่อลื่น จะส่งผลกระทบต่อเครื่องจักรอุปกรณ์ คุณภาพ การผลิต และต้นทุนค่าใช้จ่ายสูง', 'MNT', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
