INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MNT006', 'industrial-electrical-systems-fundamentals', 'พื้นฐานระบบไฟฟ้าในงานอุตสาหกรรม', 'Industrial Electrical Systems Fundamentals', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะด้านระบบไฟฟ้าและมอเตอร์ไฟฟ้าในโรงงานอุตสาหกรรม ลดความเสียหายและการหยุดขัดข้องฉุกเฉิน', 'อุปกรณ์ไฟฟ้าและมอเตอร์ไฟฟ้าเป็นเครื่องต้นกำลังหลักที่มีความสำคัญต่อกระบวนการผลิต การมีความรู้ความเข้าใจหน้าที่ การทำงาน และการบำรุงรักษาอุปกรณ์ไฟฟ้าอย่างถูกต้อง จะช่วยลดการเสียหายและการหยุดขัดข้องฉุกเฉิน ลดค่าใช้จ่ายในการซ่อมแซม และเพิ่มผลผลิต', 'MNT', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
