INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MNT007', 'safety-maintenance-practice', 'ความปลอดภัยในงานซ่อมบำรุง เชิงปฏิบัติ', 'Safety Maintenance Practice', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะด้านความปลอดภัยในงานซ่อมบำรุง มุ่งสู่เป้าหมายการเกิดอุบัติเหตุ ''ศูนย์'' อย่างยั่งยืน', 'งานซ่อมบำรุงเป็นงานที่มีความเสี่ยงสูงต่อการเกิดอุบัติเหตุ หากพนักงานและผู้ควบคุมงานขาดความรู้ความเข้าใจเกี่ยวกับความเสี่ยงและมาตรการป้องกันที่ถูกต้อง อาจนำไปสู่ความสูญเสียที่หลีกเลี่ยงได้ หลักสูตรนี้มุ่งให้ผู้เข้าอบรมเข้าใจมาตรการด้านความปลอดภัยในงานซ่อมบำรุง', 'MNT', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
