INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM001', 'preventive-maintenance', 'การบำรุงรักษาเชิงป้องกัน', 'Preventive Maintenance', 'หลักสูตรเพื่อพัฒนาระบบการบำรุงรักษาเชิงป้องกัน มุ่งสู่เป้าหมายการเสียหายของเครื่องจักรเป็นศูนย์ (Zero Failure)', 'ในอุตสาหกรรมที่ใช้เครื่องจักรเป็นหลักในการผลิต มักไม่ได้สนใจหาวิธีการใช้และบำรุงรักษาอย่างถูกต้อง ผลที่ตามมาคือเครื่องจักรเสียบ่อย เสียเวลาซ่อม และต้นทุนสูง หลักสูตรนี้เน้นการวางแผน PM จากข้อมูลและประวัติเครื่องจักรเพื่อให้แผนมีความแม่นยำ โดยมีเป้าหมายหลักคือ Zero Failure', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
