INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM002', 'total-productive-maintenance', 'บริหารการบำรุงรักษาแบบมีส่วนร่วมเพื่อเพิ่มผลผลิต', 'Total Productive Maintenance (TPM)', 'หลักสูตรแนะนำระบบ TPM ครบวงจร เพื่อให้ผู้บริหารและพนักงานทุกระดับเข้าใจหลักการ 8 เสาหลัก และขับเคลื่อน TPM ในองค์กรได้อย่างเป็นระบบ', 'ในอุตสาหกรรมยุคดิจิทัลที่มีการแข่งขันสูง องค์กรจำเป็นต้องนำระบบ TPM (Total Productive Maintenance) มาใช้ในการบริหารจัดการ ซึ่งช่วยลดความสูญเสีย เพิ่มผลผลิต และยกระดับประสิทธิภาพการทำงานอย่างต่อเนื่อง หลักสูตรนี้ออกแบบจากประสบการณ์จริงของที่ปรึกษา พร้อมตัวอย่างและวิดีโอประกอบ', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
