INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM003', 'autonomous-maintenance', 'TPM การบำรุงรักษาด้วยตนเอง', 'Autonomous Maintenance (AM)', 'หลักสูตรเชิงปฏิบัติสำหรับพัฒนาพนักงานผลิตให้สามารถดูแลและบำรุงรักษาเครื่องจักรเบื้องต้นด้วยตนเองได้อย่างเป็นระบบ ตั้งแต่ Step 0-3', 'ในโรงงานอุตสาหกรรม พนักงานผลิตที่ปฏิบัติงานหน้าเครื่องจะเห็นอาการผิดปกติของเครื่องจักรเป็นอันดับแรก หากได้รับการพัฒนาความรู้และทักษะให้สามารถดูแลและบำรุงรักษาเบื้องต้นได้ด้วยตนเอง (AM) ซึ่งเป็นหนึ่งในเสาหลักของ TPM จะช่วยลดการหยุดเครื่อง ตรวจพบความผิดปกติได้เร็ว และเพิ่มเวลาการผลิต', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
