INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM004', 'planned-maintenance', 'TPM การบำรุงรักษาตามแผน', 'Planned Maintenance (PM)', 'หลักสูตรพัฒนาระบบบำรุงรักษาตามแผน 7 ขั้นตอน สำหรับฝ่ายซ่อมบำรุง เพื่อสนับสนุนการทำ Autonomous Maintenance และมุ่งสู่เป้าหมาย Zero Breakdown', 'ใน TPM เสา PM เป็นแกนสำคัญที่สนับสนุน AM และเชื่อมโยงการทำงานกับฝ่ายผลิต จัดซื้อ เทคนิค และความปลอดภัย เพื่อยกระดับประสิทธิภาพองค์กร มุ่งเป้าหมาย Zero Breakdown และลดต้นทุนการซ่อม', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
