INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM005', 'focus-improvement', 'TPM การปรับปรุงเฉพาะเรื่องเพื่อลดความสูญเสีย', 'Focus Improvement (FI)', 'หลักสูตรเพื่อพัฒนาทักษะในการระบุปัญหา วิเคราะห์หาสาเหตุ และปรับปรุงเพื่อลดความสูญเสียในกระบวนการผลิตอย่างเป็นระบบ', 'Focused Improvement (FI) เป็นแนวทางสำคัญในการปรับปรุงงานเพื่อลดความสูญเสีย ความสูญเปล่า และต้นทุน เป็นหนึ่งในเสาหลักของ TPM ที่เน้นให้ทุกคนในองค์กรมีส่วนร่วม เพื่อสร้างวัฒนธรรมการทำงานที่เน้นการปรับปรุงอย่างไม่หยุดยั้ง', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
