INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM006', 'quality-maintenance', 'TPM การบำรุงรักษาคุณภาพเพื่อเป้าหมาย Zero Defect', 'Quality Maintenance (QM)', 'หลักสูตรพัฒนาระบบบำรุงรักษาคุณภาพ 7 ขั้นตอน ผ่าน QA Matrix เพื่อมุ่งสู่เป้าหมาย Zero Defect อย่างเป็นระบบ', 'ใน TPM ฝ่ายประกันคุณภาพมีหน้าที่พัฒนาระบบควบคุมคุณภาพอย่างต่อเนื่อง เพื่อมุ่งสู่เป้าหมาย Zero Defect โดยใช้เทคนิคการควบคุมกระบวนการผลิตอย่างเป็นระบบ และเชื่อมโยงข้อมูลระหว่างเงื่อนไขการผลิต เครื่องจักร และคุณภาพผ่าน QA Matrix', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
