INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM007', 'early-management', 'TPM การพัฒนาโครงการและผลิตภัณฑ์ใหม่', 'Early Management (EM)', 'หลักสูตรเน้นภาคปฏิบัติสำหรับฝ่ายโครงการและวิศวกรรม เพื่อออกแบบโครงการเชิงป้องกัน ลดปัญหาหน้างาน และให้เครื่องจักรหรือผลิตภัณฑ์ใหม่สามารถผลิตได้ทันทีโดยไม่มีปัญหา', 'EM (Early Management) เป็นแนวทางบริหารจัดการตั้งแต่ต้นทาง โดยวิเคราะห์ปัญหาจากการใช้งานจริง ทั้งด้านการผลิต คุณภาพ การซ่อมบำรุง และความปลอดภัย เพื่อนำมาวางแผนและออกแบบเชิงป้องกัน ช่วยให้โครงการเริ่มผลิตได้ทันที ลดปัญหาหน้างาน และเพิ่ม OEE', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
