INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM008', 'office-improvement', 'TPM การบริหารสำนักงานอย่างมีประสิทธิภาพ', 'Office Improvement (OI)', 'หลักสูตรภาคปฏิบัติสำหรับพนักงานสำนักงาน เพื่อลดความสูญเสียและสูญเปล่าในงานสำนักงาน สร้างสำนักงานให้เป็น Showroom ที่น่าทำงาน', 'สำนักงานสามารถเปรียบได้กับโรงงานการผลิตประเภทหนึ่ง เพียงแต่เปลี่ยนจากการผลิตสินค้า มาเป็นการผลิตเอกสาร การจัดการข้อมูล และการควบคุมกระบวนการต่างๆ หลักสูตรนี้นำแนวทาง FI, AM และ ET มาประยุกต์ใช้กับงานในสำนักงาน เพื่อลดความสูญเสียและเพิ่มประสิทธิภาพ', 'TPM', '1 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
