INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('TPM009', 'education-and-training', 'การอบรมพัฒนาและเสริมสร้างทักษะด้านเทคนิค', 'Education and Training Practice (ET)', 'หลักสูตร 2 วัน สำหรับสร้างระบบการอบรมและพัฒนาบุคลากรภายในองค์กร รวมถึงการสร้างวิทยากรภายใน (Train The Trainer) และจัดตั้งศูนย์อบรมพัฒนาทางเทคนิค', '"คน" คือปัจจัยสำคัญต่อกำไร ความอยู่รอด และความสามารถในการแข่งขัน เสาหลักด้านการศึกษาและอบรม (Education and Training – ET) ใน TPM ช่วยพัฒนาทักษะและศักยภาพของบุคลากรให้พร้อมรับมือกับการเปลี่ยนแปลง การอบรมนี้มุ่งเน้นการจัดระบบอบรมและพัฒนาอย่างเป็นขั้นตอน มีโครงสร้างชัดเจน เน้นการลงมือทำจริงตามหลัก TPM', 'TPM', '2 วัน', '25 คน/รุ่น', 'N/A', '', '', NULL);
