INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS003', 'maintenance-planning-kpi-evaluation', 'การวางแผนและการประเมินผลบำรุงรักษาด้วย KPI', 'Maintenance Planning and KPI Evaluation', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะการวางแผนบำรุงรักษาและการวัดผลความสำเร็จด้วย KPI ในโรงงานอุตสาหกรรม', 'การวางแผนบำรุงรักษาและการวัดผลความสำเร็จอย่างต่อเนื่องเป็นสิ่งจำเป็น ครอบคลุมตั้งแต่การบริหารจัดการเครื่องจักร การจัดการข้อมูล มาตรฐานการบำรุงรักษา การวางแผนปฏิทินงาน ไปจนถึงการวัดและประเมินผล (KPI)', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
