INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS005', 'machine-maintenance-standard-system', 'การจัดทำระบบมาตรฐานงานบำรุงรักษาเครื่องจักร อุปกรณ์การผลิต', 'Machine Maintenance Standard System Development', 'หลักสูตรเพื่อพัฒนาทักษะการเขียนและจัดทำรายการมาตรฐานการบำรุงรักษาเครื่องจักร ช่วยลดการหยุดผลิต และเพิ่มประสิทธิภาพการผลิตระยะยาว', 'หลายองค์กรยังขาดมาตรฐานในการบำรุงรักษาที่ชัดเจน ส่งผลให้เครื่องจักรขัดข้องบ่อย ซ่อมล่าช้า และสิ้นเปลืองต้นทุน การจัดทำ ''รายการมาตรฐานบำรุงรักษาเครื่องจักร'' เป็นพื้นฐานที่ช่วยให้การบำรุงรักษาทั้ง Autonomous Maintenance และ Planned Maintenance มีทิศทางเดียวกัน', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
