INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS006', 'strategic-maintenance-planning', 'การวางแผนระบบบำรุงรักษาเชิงกลยุทธ์เพื่อเป้าหมายองค์กร', 'Strategic Maintenance Planning for Organizational Goals', 'หลักสูตรเพื่อพัฒนาทักษะการวางระบบบำรุงรักษาเชิงกลยุทธ์ มุ่งสู่เป้าหมาย Zero Breakdown เพิ่ม OEE และลดค่าใช้จ่ายองค์กร', 'ยุคใหม่ได้พัฒนาระบบให้เครื่องจักรเสียฉุกเฉินเป็นศูนย์ (Zero Breakdown) โดยผู้บริหารกำหนดนโยบายให้พนักงานฝ่ายผลิตมีส่วนร่วมดูแลบำรุงรักษาเบื้องต้น ขณะที่ฝ่ายซ่อมพัฒนาระบบตั้งแต่ Proactive ไปจนถึง Predictive Maintenance หลักสูตรนี้เน้นประสบการณ์ภาคปฏิบัติจริง', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
