INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS007', 'effective-maintenance-budget-management', 'การบริหารงบประมาณงานบำรุงรักษาอย่างมีประสิทธิภาพ', 'Effective Maintenance Budget Management', 'หลักสูตรเพื่อพัฒนาทักษะการบริหารงบประมาณและลดค่าใช้จ่ายงานซ่อมบำรุง โดยไม่ลดคุณภาพและยังคงเพิ่มประสิทธิภาพการผลิต', 'ยุคที่วิกฤตเศรษฐกิจขึ้น ทุกองค์กรต้องแสวงหาโอกาสลดความสูญเสียและค่าใช้จ่ายในการซ่อมแซม โดยไม่ลดคุณภาพ และยังคงเพิ่มประสิทธิภาพการทำงานและการผลิตให้สูงขึ้น หลักสูตรนี้เน้นประสบการณ์จริงจากการวางระบบที่ประสบความสำเร็จในโรงงานอุตสาหกรรม', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
