INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS008', 'safety-management-maintenance', 'การบริหารความปลอดภัยในงานซ่อมบำรุง', 'Safety Management in Maintenance', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะการบริหารความปลอดภัยในงานซ่อมบำรุง มุ่งสู่เป้าหมายให้อุบัติเหตุเป็น ''ศูนย์''', 'อุบัติเหตุแต่ละครั้งก่อให้เกิดความเสียหายทั้งกำลังใจ ประสิทธิภาพ และคุณภาพสินค้า อุบัติเหตุรุนแรงไม่เพียงส่งผลต่อพนักงาน แต่ยังกระทบภาพลักษณ์องค์กร หลักสูตรนี้มุ่งให้ความรู้จากประสบการณ์จริง เพื่อบริหารความปลอดภัยให้อุบัติเหตุเป็น ''ศูนย์''', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
