INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS009', 'maintenance-system-performance-audit', 'การตรวจประเมินประสิทธิภาพระบบบำรุงรักษา', 'Maintenance System Performance Audit', 'หลักสูตรเพื่อพัฒนาทักษะการตรวจประเมินประสิทธิภาพระบบบำรุงรักษา ช่วยผู้บริหารและวิศวกรวิเคราะห์จุดแข็ง-จุดอ่อน และวางแผนปรับปรุงระบบ', 'การตรวจประเมินประสิทธิภาพระบบบำรุงรักษาเป็นเรื่องจำเป็น เพื่อช่วยให้ผู้บริหาร วิศวกร และหัวหน้างานได้ประเมินความสำเร็จของระบบ ติดตามผล และวิเคราะห์หาจุดแข็งจุดอ่อน เพื่อกำหนดนโยบาย วางแผน และปรับปรุงระบบให้สอดคล้องกับเป้าหมายองค์กร', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
