INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS010', 'zero-waste-production-8-techniques', 'เทคนิคการผลิตแบบไร้ของเสียด้วยแนวคิดเลข 8 (Zero Waste by 8 Techniques)', 'Zero Waste Production by 8 Techniques', 'หลักสูตรเพื่อพัฒนาทักษะการควบคุมคุณภาพการผลิต ลดของเสียให้เป็นศูนย์ ด้วยเทคนิคเลข 8 (Infinite Loop) และเครื่องมือ QA Matrix / QM Matrix', 'เป้าหมายสูงสุดของการผลิตคือการลดของเสียให้เป็นศูนย์ (Zero Defect) โดยใช้เทคนิคเลข 8 (Infinity Loop) เป็นเครื่องมือในการวิเคราะห์ ควบคุม และพัฒนาปัจจัยที่ส่งผลต่อคุณภาพ เพื่อป้องกันการเกิดของเสียตั้งแต่ต้นทาง ผ่าน QA Matrix และ QM Matrix', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
