INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('SYS011', 'maintenance-cost-budget-management', 'การบริหารต้นทุนและงบประมาณในงานซ่อมบำรุง', 'Maintenance Cost and Budget Management (RCM)', 'หลักสูตรเพื่อพัฒนาความรู้และทักษะการวัดความเชื่อมั่น (Reliability) ของเครื่องจักร และเลือกระบบบำรุงรักษาที่เหมาะสมเพื่อควบคุมต้นทุน', 'ความมั่นใจว่าเครื่องจักรจะไม่เสียหรือขัดข้องก่อนถึงรอบบำรุงรักษาครั้งถัดไปคือสิ่งสำคัญ ระบบบำรุงรักษาจึงเป็นกระบวนการตัดสินใจเลือกรูปแบบ วิธีการ และระยะเวลาที่เหมาะสม เพื่อสร้าง ''ความเชื่อมั่น'' (Reliability) ที่วัดได้เป็นเปอร์เซ็นต์', 'SYS', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
