INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MST001', 'cmm-maintenance-management', 'โปรแกรม CMM สำหรับบริหารระบบงานบำรุงรักษา (Computerized Maintenance Management System)', 'CMM Program for Maintenance Management System', 'หลักสูตร 2 วัน เรียนรู้การใช้โปรแกรม CMMS บนแอปพลิเคชันมือถือ วางแผนบำรุงรักษา จัดการวัสดุอะไหล่ ติดตามประวัติการซ่อม แจ้งเตือนอัตโนมัติ และออกใบแจ้งงานอัตโนมัติ (Auto Work Requests) รองรับ Digital Transformation และ AI สำหรับงานซ่อมบำรุง', 'ในโรงงานอุตสาหกรรม เทคโนโลยีดิจิทัลได้พลิกโฉมการทำงานอย่างรวดเร็ว การใช้โปรแกรมบริหารจัดการระบบบำรุงรักษาเครื่องจักร (CMMS) ช่วยปรับปรุงประสิทธิภาพทั้งด้านการทำงาน การผลิต และการซ่อมบำรุงเครื่องจักร ทำให้ผลผลิตเพิ่มขึ้น ลดต้นทุน และสร้างกำไรให้กับองค์กร', 'MST', '2 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
INSERT INTO course_objectives (course_id, objective, sort_order) VALUES (@course_id, 'โปรแกรม CMMS สำหรับบริหารจัดการระบบบำรุงรักษา ตามความต้องการและเหมาะสมกับองค์กรหรือบริษัท', 0);
