INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MST002', 'work-order-maintenance', 'โปรแกรม Work Order สำหรับแจ้งงานซ่อมและติดตามงาน', 'Work Order Program for Maintenance Job Request and Tracking', 'หลักสูตร 1 วัน เรียนรู้การใช้โปรแกรมสำเร็จรูป Work Order บน Microsoft 365 Access สำหรับบริหารจัดการระบบแจ้งงานซ่อม ตั้งแต่การแจ้งงาน รับงาน ซ่อมงาน ติดตามงาน จนถึงการปิดงาน อย่างเป็นระบบ (1 ท่าน ต่อ 1 เครื่องคอมพิวเตอร์)', 'ในโรงงานอุตสาหกรรม หากยังใช้วิธีเดิมในการแจ้งงานซ่อมด้วยกระดาษ การสื่อสารเพื่อติดตามงาน ตรวจสอบสถานะ ย่อมยุ่งยากและสิ้นเปลืองเวลา โปรแกรม Work Order ช่วยให้ทุกขั้นตอนเป็นระบบ ติดตามสถานะได้ทันที รายงานได้รวดเร็ว และเพิ่มประสิทธิภาพการทำงานอย่างชัดเจน', 'MST', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
