INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MST003', 'pmtech-maintenance-planning', 'โปรแกรม PMTECH สำหรับวางแผนงานบำรุงรักษา', 'PMTECH Program for Preventive Maintenance Planning', 'หลักสูตร 1 วัน เรียนรู้การใช้โปรแกรม PMTECH จัดทำระบบบำรุงรักษาเชิงป้องกัน (PM) ฐานข้อมูลเครื่องจักร มาตรฐานการบำรุงรักษา (WI) การวางแผนปฏิทินบำรุงรักษา และการจัดการวัสดุอะไหล่ (1 ท่าน ต่อ 1 เครื่องคอมพิวเตอร์)', 'ในโรงงานอุตสาหกรรม การใช้คอมพิวเตอร์บริหารจัดการระบบบำรุงรักษาเครื่องจักร (CMMS) ช่วยให้การบำรุงรักษามีความเป็นระบบ ใช้งานได้ง่าย สะดวก และรวดเร็ว สนับสนุนการจัดทำฐานข้อมูลเครื่องจักร มาตรฐานการบำรุงรักษา การวางแผนและควบคุมงานซ่อมบำรุงอย่างมีประสิทธิภาพ', 'MST', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
