INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MST004', 'kpi-maintenance-history-budget', 'โปรแกรมสำหรับบันทึกประวัติซ่อม บริหารงบประมาณ และประเมินผล', 'KPI''s Maintenance Program for Repair History, Budget Management and Evaluation', 'หลักสูตร 1 วัน เรียนรู้การใช้โปรแกรม KPI''s Maintenance บันทึกประวัติซ่อม คำนวณ OEE, MTBF, MTTR, MAF, RF จัดทำรายงานค่าใช้จ่ายซ่อมบำรุง และงบประมาณซ่อมบำรุงแต่ละหน่วยงาน (1 ท่าน ต่อ 1 เครื่องคอมพิวเตอร์)', 'สิ่งจำเป็นอย่างยิ่งของการจัดทำระบบซ่อมบำรุงที่ขาดไม่ได้ คือ "ประวัติการซ่อม และการวัด–ประเมินระบบซ่อมบำรุง" เพื่อติดตามผล ประเมินความสำเร็จ ค้นหาจุดแข็งและจุดอ่อน รวมถึงใช้เป็นสถิติข้อมูลสำคัญในการวางแผนในอนาคต', 'MST', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
