INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MST005', 'spare-parts-management', 'โปรแกรมคลังอะไหล่อัตโนมัติสำหรับงานซ่อมบำรุง', 'Spare Parts Maintenance Management Program', 'หลักสูตร 1 วัน เรียนรู้การใช้โปรแกรมคลังอะไหล่อัตโนมัติ (MS Access) บริหารจัดการวัสดุและอะไหล่ซ่อมบำรุงอย่างเป็นระบบ ควบคุมสต๊อก กำหนดจุดสั่งซื้อ (OP) และออกรายงานประสิทธิภาพการหมุนเวียน', 'ในโรงงานอุตสาหกรรม ปัจจัยสำคัญอย่างหนึ่งของการบริหารระบบซ่อมบำรุงให้มีประสิทธิภาพ คือ การจัดการระบบวัสดุและอะไหล่ซ่อมบำรุง การนำโปรแกรมคอมพิวเตอร์มาประยุกต์ใช้ช่วยให้การบริหารเป็นไปอย่างมีระบบ ลดค่าใช้จ่าย ลดจำนวนเงินจม และดอกเบี้ยจากวัสดุและอะไหล่คงคลัง', 'MST', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
