INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA001', 'root-cause-analysis', 'การวิเคราะห์หาสาเหตุรากของปัญหา (Root Cause Analysis)', 'Root Cause Analysis', 'หลักสูตร 1 วัน เรียนรู้เทคนิคและเครื่องมือการวิเคราะห์สาเหตุที่แท้จริงของปัญหาหลากหลายรูปแบบ (Cause & Effect Diagram, Why-Why Analysis, PM Analysis, FMEA, VDO Analysis, AI Analysis) เพื่อป้องกันการเกิดซ้ำ', 'ในโรงงานอุตสาหกรรม ปัญหาที่เกิดขึ้นในกระบวนการผลิต การทำงาน และงานบำรุงรักษา หากไม่สามารถระบุและแก้ไขที่สาเหตุที่แท้จริงได้อย่างตรงจุด ปัญหาเดิมก็จะเกิดซ้ำ การเลือกใช้เทคนิคและเครื่องมือการวิเคราะห์สาเหตุอย่างเหมาะสมจะช่วยให้ค้นหาต้นตอได้รวดเร็วและแม่นยำ', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
