INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA002', '5-why-analysis', 'การวิเคราะห์ปัญหาแบบ 5 Why', '5 Why Analysis', 'หลักสูตร 1 วัน เรียนรู้เทคนิคการวิเคราะห์ปัญหาอย่างเป็นระบบด้วย Why-Why Analysis เพื่อค้นหาต้นตอของปัญหาที่แท้จริงจากเครื่องจักร อุปกรณ์ หรือกระบวนการผลิต พร้อมฝึกปฏิบัติจากสถานการณ์จริง', 'การวิเคราะห์ปัญหาจำเป็นต้องค้นหาต้นเหตุอย่างเป็นระบบ โดยใช้ประสบการณ์ ทักษะ และการตั้งคำถาม "ทำไม...ทำไม" (Why-Why Analysis) กับเหตุการณ์ที่เกิดขึ้น เพื่อสืบหาต้นตอของปัญหาที่แท้จริง', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
