INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA003', 'physical-mechanism-analysis', 'การวิเคราะห์กลไกทางกายภาพ (Physical Mechanism Analysis)', 'Physical Mechanism Analysis (PM Analysis)', 'หลักสูตร 1 วัน เรียนรู้การใช้ PM Analysis เพื่อวิเคราะห์เชิงลึกในด้านกลไก โครงสร้าง และส่วนประกอบของเครื่องจักร ด้วย 8 ขั้นตอน เพื่อขจัดปัญหาเรื้อรังอย่างยั่งยืน', 'ความสูญเสียและปัญหาที่เกิดขึ้นซ้ำซากเรื้อรัง แก้ไม่หายขาด มักเกิดจากการใช้เครื่องมือวิเคราะห์แบบเดิมที่ไม่สามารถเข้าถึงต้นตอของปัญหาได้ PM Analysis ช่วยวิเคราะห์เชิงวิศวกรรมเพื่อตรวจสอบสิ่งผิดปกติที่แฝงอยู่และนำไปสู่การแก้ไขอย่างตรงจุดและยั่งยืน', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
