INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA004', 'fmea', 'การวิเคราะห์ข้อบกพร่อง สิ่งผิดปกติ และผลกระทบอย่างเป็นระบบ (FMEA)', 'Failure Mode and Effect Analysis (FMEA)', 'หลักสูตร 1 วัน เรียนรู้การจัดทำ Process-FMEA การคำนวณ RPN (Risk Priority Number) และการใช้แบบฟอร์ม FMEA เพื่อป้องกันความผิดพลาดในกระบวนการผลิต การบริการ และงานบำรุงรักษา', 'FMEA (Failure Mode and Effect Analysis) เป็นเครื่องมือสำคัญที่ช่วยวิเคราะห์และประเมินความเสี่ยงที่อาจเกิดขึ้นจากข้อบกพร่องในกระบวนการต่างๆ สามารถนำมาประยุกต์ใช้ได้อย่างมีประสิทธิภาพในทุกประเภทของงาน', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
