INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA005', 'component-failure-analysis', 'การวิเคราะห์การเสียหายของชิ้นส่วนเครื่องจักร', 'Machine Component Failure Analysis', 'หลักสูตร 1 วัน เรียนรู้การวิเคราะห์รูปแบบและสาเหตุความเสียหายของชิ้นส่วนเครื่องจักร (แบริ่ง เฟือง สายพาน โซ่ขับ ซีล สารหล่อลื่น ฯลฯ) พร้อมแนวทางแก้ไขและป้องกันปัญหาซ้ำซาก', 'การเสียหาย ขัดข้อง สึกหรอ แตกร้าว หรือหักขาดของชิ้นส่วนเครื่องจักร หากไม่วิเคราะห์หาสาเหตุที่แท้จริง กลับเลือกวิธีถอด-เปลี่ยน-ประกอบใหม่ ปัญหาก็จะเกิดซ้ำ ทำให้เครื่องจักรขัดข้องบ่อย ต้นทุนเพิ่ม และเวลาการผลิตสูญเสีย', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
