INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA006', 'motor-problem-analysis', 'การวิเคราะห์และป้องกันปัญหามอเตอร์', 'Motor Problem Analysis and Prevention', 'หลักสูตร 1 วัน เรียนรู้การวิเคราะห์สาเหตุปัญหาของมอเตอร์ไฟฟ้าด้วย Why-Why Analysis และการฝึกภาคปฏิบัติตรวจวัดสุขภาพมอเตอร์ (เสียง อุณหภูมิ การสั่นสะเทือน ความเสียหายแบริ่ง)', 'มอเตอร์เป็นเครื่องต้นกำลังที่สำคัญในโรงงานอุตสาหกรรม หากมีความรู้และความเข้าใจในการวิเคราะห์และแก้ไขปัญหาที่เกิดจากมอเตอร์ จะช่วยวางแผนบำรุงรักษาได้เหมาะสม ลดความเสี่ยง Breakdown ยืดอายุการใช้งาน และลดต้นทุน', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
