INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA007', 'bearing-problem-analysis', 'การวิเคราะห์และป้องกันปัญหาแบริ่ง', 'Bearing Problem Analysis and Prevention', 'หลักสูตร 1 วัน เรียนรู้โครงสร้างและประเภทของตลับลูกปืน การถอดและประกอบอย่างถูกต้อง การวิเคราะห์สาเหตุความเสียหาย และการวัดการสั่นสะเทือนเพื่อประเมินความเสียหายของแบริ่ง', 'แบริ่งหรือตลับลูกปืนเป็นชิ้นส่วนสำคัญของเครื่องจักรที่มีการหมุนเคลื่อนที่ หากเลือกใช้ไม่เหมาะสม ประกอบไม่ถูกต้อง หรือขาดการบำรุงรักษา ย่อมนำไปสู่ปัญหา Breakdown สูญเสียประสิทธิภาพการผลิต และเกิดค่าใช้จ่ายสูงโดยไม่จำเป็น', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
INSERT INTO course_objectives (course_id, objective, sort_order) VALUES (@course_id, 'เพื่อความเข้าใจหน้าที่ของส่วนประกอบตลับลูกปืน พร้อมสามารถเลือกใช้งานได้อย่างเหมาะสม', 0);
INSERT INTO course_objectives (course_id, objective, sort_order) VALUES (@course_id, 'สามารถระบุขนาดและพิกัดของตลับลูกปืนจากอนุกรมมาตรฐานได้อย่างแม่นยำ', 1);
