INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('ANA008', 'qc-7-tools', 'เทคนิคการใช้ QC 7 Tools เพื่อการปรับปรุงงาน', 'QC 7 Tools for Work Improvement', 'หลักสูตร 1 วัน เรียนรู้การใช้เครื่องมือ QC 7 Tools ได้แก่ Check Sheet, Bar Chart, Pareto Diagram, Cause and Effect Diagram, Histogram, Scatter Diagram และ Control Chart เพื่อวิเคราะห์และแก้ไขปัญหาอย่างเป็นระบบ', 'การเลือกใช้เครื่องมือวิเคราะห์และแก้ไขปัญหา QC 7 Tools อย่างเหมาะสมกับปัญหาจำเป็นต้องมีแนวคิดในการวางแผนจัดเก็บและจำแนกข้อมูลอย่างเหมาะสมตั้งแต่ต้น เพื่อป้องกันความผิดพลาดและลดการสูญเสียเวลา', 'ANA', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
