INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP001', '7-wastes-reduction', 'การลดความสูญเสีย 7 ประการ (7 Wastes Reduction)', '7 Wastes Reduction', 'หลักสูตร 1 วัน เรียนรู้การระบุและขจัดความสูญเสีย 7 ประการในกระบวนการทำงาน เพื่อเพิ่มผลผลิต ลดต้นทุน และส่งมอบได้ทันเวลา', 'การเพิ่มผลผลิต ลดต้นทุน และส่งมอบได้ทันเวลา สามารถทำให้องค์การลดความสูญเสียทุกรูปแบบในกระบวนการทำงานทุกสายงาน หากไม่ให้ความสนใจสังเกตและพยายามปรับปรุงแก้ไข ความสูญเสียก็ยิ่งเพิ่มขึ้น การลดความสูญเสียถือเป็นหน้าที่ของพนักงานและผู้บริหารทุกคน', 'IMP', '1 วัน', '20 คน/รุ่น', 'N/A', '', '', NULL);
