INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP002', 'cost-reduction', 'เทคนิคการลดต้นทุน (Cost Reduction)', 'Cost Reduction Techniques', 'หลักสูตร 1 วัน เรียนรู้เทคนิคและเครื่องมือในการวิเคราะห์และลดต้นทุนอย่างเป็นระบบ เพื่อเพิ่มผลกำไรและความสามารถในการแข่งขันขององค์กร', 'ปัจจุบันต้นทุนคือสิ่งสำคัญในการดำเนินกิจกรรมทางธุรกิจ เนื่องจากการแข่งขันที่สูงและสภาวะเปลี่ยนแปลงรวดเร็ว องค์กรควรให้ความสำคัญในการปรับปรุงต้นทุนอย่างต่อเนื่องโดยมุ่งค้นหาและขจัดความสูญเสีย โดยคุณภาพของสินค้าและบริการต้องไม่ลดลง', 'IMP', '1 วัน', '20 คน/รุ่น', 'N/A', '', '', NULL);
