INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP003', 'lean-manufacturing', 'ระบบการผลิตแบบลีน (Lean Manufacturing)', 'Lean Manufacturing', 'หลักสูตร 1 วัน เรียนรู้แนวคิดและหลักการของการผลิตแบบลีน รวมถึงการใช้ Value Stream Mapping เพื่อวิเคราะห์และปรับปรุงกระบวนการสร้างคุณค่าให้แก่ลูกค้าอย่างต่อเนื่อง', 'การดำเนินธุรกิจในปัจจุบันต้องเผชิญกับการแข่งขันที่รุนแรง ต้นทุนการผลิตปรับตัวสูงขึ้น ระบบการผลิตแบบลีนช่วยลดต้นทุน รองรับการเปลี่ยนแปลง และลดความสูญเสียตลอดกระบวนการทำงาน ตั้งแต่การออกแบบจนถึงการจัดจำหน่าย', 'IMP', '1 วัน', '20 คน/รุ่น', 'N/A', '', '', NULL);
