INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP004', 'proactive-maintenance', 'ระบบบำรุงรักษาเชิงรุกเพื่อป้องกันปัญหาเครื่องจักร', 'Proactive Maintenance System', 'หลักสูตร 1 วัน เรียนรู้การวิเคราะห์จากประสบการณ์จริง เพื่อเข้าใจสาเหตุการเสียซ้ำและแนวทางการบำรุงรักษาเชิงรุก (Proactive Maintenance) สำหรับยืดอายุเครื่องจักรและลดการหยุดเครื่อง', 'ในโรงงานอุตสาหกรรม เครื่องจักรและอุปกรณ์เปรียบเสมือนร่างกายของคน หากสามารถวิเคราะห์ หยั่งรู้ รู้ทันปัญหาตั้งแต่ต้นตอของความเสียหาย แล้วบำรุงรักษาเชิงรุกก่อนการใช้งาน จะช่วยยืดอายุการใช้งาน เพิ่มความน่าเชื่อถือ ลดการขัดข้องซ้ำซาก และลดต้นทุน', 'IMP', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
