INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP005', 'predictive-maintenance-practice', 'การพยากรณ์งานบำรุงรักษาเชิงปฏิบัติ', 'Predictive Maintenance in Practice', 'หลักสูตร 1 วัน เรียนรู้หลักการและขั้นตอนการจัดทำระบบบำรุงรักษาเชิงพยากรณ์ (Predictive Maintenance) เครื่องมือตรวจวัดสุขภาพเครื่องจักร และเกณฑ์ตัดสินสถานะสุขภาพ', 'ในโรงงานอุตสาหกรรม การรู้สุขภาพของเครื่องจักรล่วงหน้าเป็นสิ่งสำคัญ ระบบบำรุงรักษาเชิงพยากรณ์ (PdM) ช่วยติดตามสุขภาพเครื่องจักร ทำให้วางแผนซ่อมก่อนเกิดปัญหา ลดการหยุดงาน ลดค่าใช้จ่าย และเพิ่มประสิทธิภาพ', 'IMP', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
