INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP006', 'corrective-maintenance', 'การแก้ไขและปรับปรุงระบบบำรุงรักษาเครื่องจักร (Corrective Maintenance: CM)', 'Corrective Maintenance (CM)', 'หลักสูตร 1 วัน เรียนรู้ 10 ขั้นตอนของ Corrective Maintenance การวิเคราะห์สาเหตุความเสียหาย และเทคนิคการแก้ไขเพื่อป้องกันการขัดข้องซ้ำ มุ่งสู่เป้าหมาย Maintenance Free', 'Corrective Maintenance (CM) ไม่ใช่เพียงการซ่อมแซมเมื่ออุปกรณ์เสียหาย แต่คือการวิเคราะห์และขจัดสาเหตุของความเสียหาย เพื่อป้องกันการขัดข้องซ้ำ เพิ่มความน่าเชื่อถือ ยืดอายุการใช้งาน และลดต้นทุนโดยรวม', 'IMP', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
