INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP007', 'visual-control-maintenance', 'การบำรุงรักษาเชิงมองเห็น (Visual Control Maintenance)', 'Visual Control Maintenance', 'หลักสูตร 1 วัน เรียนรู้การออกแบบและจัดทำระบบบำรุงรักษาเครื่องจักรด้วยวิธีมองเห็น (Visual Control) ทั้ง 6 ประเภทงาน เพื่อเพิ่มประสิทธิภาพการผลิตและลดการขัดข้องของเครื่องจักร', 'Visual Control เป็นเครื่องมือสำคัญในการสื่อสารและสร้างความเข้าใจร่วมกันผ่านสิ่งที่มองเห็นได้ทันที ช่วยให้ทุกคนสามารถตัดสินใจได้อย่างรวดเร็วว่ากระบวนการผลิตหรือสถานะของเครื่องจักรอยู่ในภาวะปกติหรือผิดปกติ', 'IMP', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
