INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP008', 'maintenance-quality-warranty', 'การควบคุมคุณภาพงานซ่อมด้วยระบบรับประกันงาน', 'Maintenance Quality Control with Warranty System', 'หลักสูตร 1 วัน เรียนรู้ 6 มาตรการสู่ระบบประกันงานซ่อม ปัจจัยสำคัญของงานซ่อมที่มีคุณภาพ (4O) และการควบคุมคุณภาพงานซ่อมในแต่ละขั้นตอนเพื่อสร้างความมั่นใจในประสิทธิภาพเครื่องจักรหลังการซ่อม', 'เช่นเดียวกับสินค้าที่มีการประกันคุณภาพ งานซ่อมบำรุงก็สามารถจัดทำเป็นระบบประกันงานซ่อมได้ โดยมีขั้นตอนและกระบวนการที่ชัดเจนตั้งแต่เริ่มต้นจนถึงปลายทาง เพื่อสร้างความมั่นใจในประสิทธิภาพของเครื่องจักรหลังการซ่อม', 'IMP', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
