INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP009', 'maintenance-kpi', 'การวัดประสิทธิภาพของระบบซ่อมบำรุง (Maintenance KPI)', 'Maintenance KPI', 'หลักสูตร 1 วัน เรียนรู้การวางแผนบำรุงรักษาในรูปแบบปฏิทินงาน การกำหนดและประเมินผลตัวชี้วัด (KPI) เช่น MAF, RF, BD, MTBF, MTTR, OEE เพื่อพัฒนาระบบบำรุงรักษาอย่างต่อเนื่อง', 'การทำให้เครื่องจักรทำงานได้อย่างมีประสิทธิภาพต้องอาศัยการวางแผนการบำรุงรักษาอย่างเป็นระบบ รวมถึงการติดตามและวัดผลความสำเร็จอย่างต่อเนื่องด้วยตัวชี้วัด (KPI) เพื่อประเมินและพัฒนาให้ดียิ่งขึ้น', 'IMP', '1 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
