INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('IMP010', 'ram-analysis', 'การวิเคราะห์ความน่าเชื่อถือ ความพร้อมใช้งาน และความสามารถในการซ่อมบำรุง', 'Reliability Availability Maintainability (RAM Analysis)', 'หลักสูตร 2 วัน เรียนรู้หลักการ RAM (Reliability, Availability, Maintainability) การวิเคราะห์และประเมินผลอย่างเป็นระบบ รวมถึงการพัฒนาเครื่องจักรเพื่อลดต้นทุนและเพิ่มผลผลิต', 'การวิเคราะห์และพัฒนาเครื่องจักร อุปกรณ์ หรือการลงทุนในโครงการใหม่ โดยอาศัยหลักความน่าเชื่อถือ ความพร้อมใช้งาน และความสามารถในการบำรุงรักษา จะช่วยให้เครื่องจักรมีประสิทธิภาพมากขึ้น ทั้งการลดค่าใช้จ่าย ลดต้นทุน และเพิ่มผลผลิต', 'IMP', '2 วัน', '15 คน/รุ่น', 'N/A', '', '', NULL);
