INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MRM001', 'condition-monitoring-predictive-maintenance', 'พื้นฐานการบำรุงรักษาเครื่องจักรด้วยเทคโนโลยีการบำรุงรักษาเชิงคาดการณ์', 'Basic Condition Based Maintenance', 'หลักสูตร 2 วัน สำหรับการตรวจสภาพเครื่องจักรด้วยเทคโนโลยี Predictive Maintenance ได้แก่ การวิเคราะห์การสั่นสะเทือน Thermography และการวิเคราะห์น้ำมัน เพื่อลดการหยุดเครื่องที่ไม่พึงประสงค์', 'โรงงานอุตสาหกรรมต่างเผชิญกับความท้าทายในการรักษาความพร้อมใช้งานของเครื่องจักร การบำรุงรักษาเชิงคาดการณ์ (Predictive Maintenance) และการตรวจสภาพเชิงเงื่อนไข (Condition-Based Maintenance: CBM) เป็นแนวทางสำคัญในการบริหารจัดการเครื่องจักรให้เกิดความเชื่อมั่น โดยอาศัยข้อมูลจากการวิเคราะห์การสั่นสะเทือน การถ่ายภาพความร้อน และการวิเคราะห์คุณภาพน้ำมัน', 'MRM', '2 วัน', '20 คน/รุ่น', 'N/A', '', '', NULL);
