INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MRM004', 'machine-shaft-alignment', 'การแก้ไขปัญหาการเยื้องศูนย์', 'Machine Shaft Alignment and Workshop', 'หลักสูตร 2 วัน เน้นภาคปฏิบัติสำหรับการตั้งศูนย์เครื่องจักร ครอบคลุมตั้งแต่ Dial Indicators, Reverse Dial จนถึง Laser Alignment เพื่อลดการสั่นสะเทือนและเพิ่มอายุการใช้งานเครื่องจักร', 'การเยื้องศูนย์ของเพลาเครื่องจักร (Shaft Misalignment) เป็นหนึ่งในปัจจัยหลักที่ทำให้เกิดความสั่นสะเทือน ความเสียหายของชิ้นส่วน และการหยุดทำงานที่ไม่พึงประสงค์ หลักสูตรนี้จัดขึ้นเพื่อให้ผู้ปฏิบัติงานด้านซ่อมบำรุงได้เข้าใจถึงหลักการตั้งศูนย์เครื่องจักรอย่างถูกต้อง พร้อมการอบรมเชิงปฏิบัติ', 'MRM', '2 วัน', '20 คน/รุ่น', 'N/A', '', '', NULL);
