INSERT INTO courses (course_code, slug, title, english_title, short_desc, description, category_code, duration, capacity, price, badge, badge_class, image) VALUES ('MRM005', 'balancing-rotating-machine', 'การปรับสมดุลเครื่องจักรหมุน', 'Balancing of Rotating Machine and Workshop', 'หลักสูตรเพื่อทำความเข้าใจสาเหตุการเกิดความไม่สมดุลของเครื่องจักร และฝึกเทคนิคการถ่วงสมดุลแบบภาคสนาม (Field Balancing) เพื่อลดการสั่นสะเทือนและเพิ่มอายุการใช้งานเครื่องจักร', 'การไม่สมดุล (Unbalance) เป็นสาเหตุสำคัญที่ทำให้เครื่องจักรหมุนเกิดการสั่นสะเทือน สูญเสียประสิทธิภาพ และลดอายุการใช้งาน หลักสูตรนี้จัดทำขึ้นเพื่อให้ผู้เข้าร่วมเข้าใจสาเหตุและผลกระทบของการไม่สมดุล รวมถึงเรียนรู้เทคนิคการถ่วงสมดุลแบบภาคสนาม (Field Balancing) ที่สามารถนำไปประยุกต์ใช้กับเครื่องจักรในโรงงานได้จริง', 'MRM', '1 วัน', '20 คน/รุ่น', 'N/A', '', '', NULL);
